select id,name,unit,title,field,expert_type,weight,guidance_count,last_invite,status from experts

    and name like concat('%',#{name},'%')
    and status=#{status} 
    and expert_type=#{expertType}
    and weight=#{weight}

select * from experts

    and name like concat('%',#{name},'%')
    and status=#{expStatus} 
    and expert_type=#{expertType}
